def test_flag_default_is_processed_separately_from_activation(runner):
    @click.command()
    @click.option("--value", flag_value="flag", default=True, type=click.STRING)
    def cli(value):
        click.echo(value)

    result = runner.invoke(cli, [])
    assert not result.exception
    assert result.output == "True\n"

    result = runner.invoke(cli, ["--value"])
    assert not result.exception
    assert result.output == "flag\n""}]}
